var e=[{id:`L2_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`……가면 안 될까?`,JPN:`……行くのはダメかな？`,ENG:`...let go of me first?`,TWN:`……再走嗎？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_B`,text:{KOREA:`드르렁…… 피유…….`,JPN:`ぐう……プフ……`,ENG:`Zzz... Groarghhhrr...`,TWN:`呼嚕嚕……咻咻……`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`……어어?`,JPN:`……あれ？`,ENG:`...H-huh?`,TWN:`……嗯？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_HORN_FAKE`,text:{KOREA:`잠들었어. 빨리 도망가자.`,JPN:`眠った。早く逃げよう。`,ENG:`They’re asleep. We should run away now.`,TWN:`他們睡著了，我們快逃吧！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_HORN_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`잠들었다고? 이렇게 갑자기?`,JPN:`眠った？　こんなにいきなり？`,ENG:`They fell asleep? Just like that?`,TWN:`睡著了？這麼突然？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_HORN_FAKE`,text:{KOREA:`뒤는 이곳 사람들에게 맡기고, 빨리!`,JPN:`あとはここの人たちに任せて、早く！`,ENG:`Let’s leave the rest to the others. We need to get going!`,TWN:`後面的事就交給這裡的人處理，動作快！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NIGHTMARE_DREAM_HORN_FAKE`,face:`UNIT_SERIOUS`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`아, 알겠어!`,JPN:`わ、わかった！`,ENG:`O-okay!`,TWN:`喔…好！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SPEAR_MAID_DREAM_FAKE`,text:{KOREA:`이 진상들 지금 여기서 잠든 거야?`,JPN:`この無礼者、ここで寝るわけ？`,ENG:`Did these idiots just fall asleep?`,TWN:`這些無賴是在這裡睡覺嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SPEAR_MAID_DREAM_FAKE`,text:{KOREA:`방해되니까 치워 놓고 올게.`,JPN:`邪魔だからちょっと片付けてくるね。`,ENG:`They’re kinda in the way, so I’ll move them.`,TWN:`真礙事，我去把他們弄走。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SPEAR_MAID_DREAM_FAKE`,text:{KOREA:`안 그래도 임무 때문에 바빠 죽겠는데……!`,JPN:`ただでさえ任務で忙しいのに……！`,ENG:`I’m already busy with the mission as it is...!`,TWN:`真會找麻煩，我還有任務要忙欸……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_A`,text:{KOREA:`윽. 머리가…….`,JPN:`うっ。頭が……`,ENG:`Ugh! My head...`,TWN:`呃，我的頭……`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SMILE_NPC_OZ_A`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_B`,text:{KOREA:`으아아악!`,JPN:`うわああっ！`,ENG:`Aaaack!`,TWN:`呃啊啊啊！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SMILE_NPC_OZ_B`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_B`,text:{KOREA:`괴물… 저기 괴물이……!`,JPN:`バケモン……あそこにバケモンが……！`,ENG:`M-monster...! There’s a monster!`,TWN:`怪物…有怪物……！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SMILE_NPC_OZ_B`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_A`,text:{KOREA:`……너도 악몽을 꿨나 보군. 진정해. 여긴 꿈이 아니니까.`,JPN:`……お前も悪夢を見たか。落ち着け。ここは夢じゃないぞ。`,ENG:`You also had a nightmare, I see. Calm down. This isn’t a dream.`,TWN:`……你也做惡夢啦？冷靜點，現在不是在夢裡。`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SMILE_NPC_OZ_A`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_B`,text:{KOREA:`……저, 정말이네? 여긴 어디야?`,JPN:`……ほ、ホントだ。ここはどこだ？`,ENG:`R-really? Then where am I?`,TWN:`…是…是嗎？這裡是哪裡？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SMILE_NPC_OZ_B`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SMILE_NPC_OZ_A`,text:{KOREA:`근처 뒷골목인 듯하군.`,JPN:`近くの裏道っぽいな。`,ENG:`We’re in a back alley somewhere.`,TWN:`應該是附近的暗巷吧。`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SMILE_NPC_OZ_A`,face:`UNIT_IDLE`},R:null}}}];export{e as default};